// Combine all items into a single text for the LLM
const items = $input.all();

if (!items || items.length === 0) {
  return [{
    json: {
      posts: 'No new articles found for today.',
      date: new Date().toISOString().split('T')[0],
      itemCount: 0,
      urls: []
    }
  }];
}

const postsText = items.map((item, index) => {
  const json = item.json;
  return `### Post ${index + 1}
**Title:** ${json.title}
**Source:** ${json.source_name} (${json.category})
**Date:** ${json.pub_date}
**Link:** ${json.url}
**Content Preview:** ${json.content_snippet || 'No content'}
`;
}).join('\n---\n');

// Collect URLs for marking as processed later
const urls = items.map(item => item.json.url);

return [{
  json: {
    posts: postsText,
    date: new Date().toISOString().split('T')[0],
    itemCount: items.length,
    urls: urls
  }
}];

const item = $input.first();
// AI Agent outputs to 'output' field, chainLlm outputs to 'text'
const text = item.json.output || item.json.text || '';
const urls = $('Prepare for LLM').first().json.urls || [];
const maxLength = 1900;
const maxBlocks = 98;

function parseRichText(text) {
  const segments = [];
  let remaining = text;

  while (remaining.length > 0) {
    const boldMatch = remaining.match(/^\*\*(.+?)\*\*/);
    const italicMatch = remaining.match(/^\*(.+?)\*/);
    const codeMatch = remaining.match(/^`(.+?)`/);
    const linkMatch = remaining.match(/^\[(.+?)\]\((.+?)\)/);

    if (boldMatch) {
      segments.push({ type: 'text', text: { content: boldMatch[1] }, annotations: { bold: true } });
      remaining = remaining.substring(boldMatch[0].length);
    } else if (codeMatch) {
      segments.push({ type: 'text', text: { content: codeMatch[1] }, annotations: { code: true } });
      remaining = remaining.substring(codeMatch[0].length);
    } else if (linkMatch) {
      segments.push({ type: 'text', text: { content: linkMatch[1], link: { url: linkMatch[2] } } });
      remaining = remaining.substring(linkMatch[0].length);
    } else if (italicMatch && !remaining.startsWith('**')) {
      segments.push({ type: 'text', text: { content: italicMatch[1] }, annotations: { italic: true } });
      remaining = remaining.substring(italicMatch[0].length);
    } else {
      const nextSpecial = remaining.search(/\*|`|\[/);
      const plainEnd = nextSpecial === -1 ? remaining.length : nextSpecial;
      if (plainEnd > 0) {
        segments.push({ type: 'text', text: { content: remaining.substring(0, plainEnd) } });
        remaining = remaining.substring(plainEnd);
      } else {
        segments.push({ type: 'text', text: { content: remaining[0] } });
        remaining = remaining.substring(1);
      }
    }
  }

  return segments.length > 0 ? segments : [{ type: 'text', text: { content: text } }];
}

function splitRichText(segments) {
  const result = [];
  let current = [];
  let currentLen = 0;

  for (const seg of segments) {
    const content = seg.text.content;
    if (currentLen + content.length <= maxLength) {
      current.push(seg);
      currentLen += content.length;
    } else {
      if (current.length > 0) result.push(current);
      current = [seg];
      currentLen = content.length;
    }
  }
  if (current.length > 0) result.push(current);
  return result;
}

const lines = text.split('\n');
const children = [];

for (const line of lines) {
  if (children.length >= maxBlocks) break;

  const trimmed = line.trim();
  if (!trimmed) continue;

  if (trimmed.startsWith('# ')) {
    children.push({ object: 'block', type: 'heading_1', heading_1: { rich_text: parseRichText(trimmed.substring(2)) } });
  } else if (trimmed.startsWith('## ')) {
    children.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: parseRichText(trimmed.substring(3)) } });
  } else if (trimmed.startsWith('### ')) {
    children.push({ object: 'block', type: 'heading_3', heading_3: { rich_text: parseRichText(trimmed.substring(4)) } });
  } else if (trimmed === '---' || trimmed === '***' || trimmed === '___') {
    children.push({ object: 'block', type: 'divider', divider: {} });
  } else if (trimmed.startsWith('- ')) {
    const richText = parseRichText(trimmed.substring(2));
    const chunks = splitRichText(richText);
    for (const chunk of chunks) {
      if (children.length >= maxBlocks) break;
      children.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: chunk } });
    }
  } else if (/^\d+\.\s/.test(trimmed)) {
    const content = trimmed.replace(/^\d+\.\s/, '');
    children.push({ object: 'block', type: 'numbered_list_item', numbered_list_item: { rich_text: parseRichText(content) } });
  } else {
    const richText = parseRichText(trimmed);
    const chunks = splitRichText(richText);
    for (const chunk of chunks) {
      if (children.length >= maxBlocks) break;
      children.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: chunk } });
    }
  }
}

return [{ json: { notionChildren: children, date: new Date().toISOString().split('T')[0], urls: urls } }];
